class CancelReservationView(View):
    def post(self, request, codigo):
        try:
            reserva = Reserva.objects.get(codigo_seguimiento=codigo)
        except Reserva.DoesNotExist:
            messages.error(request, 'Reserva no encontrada.')
            return redirect('reservations:track')

        if reserva.estado != 'PENDIENTE_DE_PAGO':
            messages.error(request, 'Solo se pueden cancelar reservas pendientes de pago.')
            return redirect('reservations:track_detail', codigo=codigo)

        estado_anterior = reserva.estado
        reserva.delete()

        asunto = f'Cancelación de Reserva - Código: {codigo}'
        mensaje = f'''Hola {reserva.nombre_cliente},

Tu reserva ha sido cancelada exitosamente.

Detalles de la Reserva Cancelada:
- Código de Seguimiento: {codigo}
- Barco: {reserva.barco.nombre}
- Fecha de Inicio: {reserva.fecha_inicio}
- Fecha de Fin: {reserva.fecha_fin}
- Importe Total: {reserva.importe_total}€

Gracias por usar Hundidos.
'''

        try:
            send_mail(
                asunto,
                mensaje,
                settings.DEFAULT_FROM_EMAIL,
                [reserva.email_cliente],
                fail_silently=True,
            )
        except:
            pass

        messages.success(request, 'Reserva cancelada exitosamente.')
        return redirect('reservations:track')


