{% block content %}
<div class="detail-container">
    <h2>Detalles de Reserva</h2>

    <div class="reserva-info">
        <div>
            {% if reserva.estado == 'PENDIENTE_DE_PAGO' %}
                <span class="estado-badge estado-pendiente">{{ reserva.get_estado_display }}</span>
            {% elif reserva.estado == 'PAGADO' %}
                <span class="estado-badge estado-pagado">{{ reserva.get_estado_display }}</span>
            {% elif reserva.estado == 'EN_USO' %}
                <span class="estado-badge estado-en-uso">{{ reserva.get_estado_display }}</span>
            {% elif reserva.estado == 'DEVUELTO' %}
                <span class="estado-badge estado-devuelto">{{ reserva.get_estado_display }}</span>
            {% elif reserva.estado == 'CANCELADA' %}
                <span class="estado-badge estado-cancelada">{{ reserva.get_estado_display }}</span>
            {% endif %}
        </div>

        <div class="info-grid">
            <div class="info-item">
                <div class="info-label">Código de Seguimiento</div>
                <div class="info-valor">{{ reserva.codigo_seguimiento }}</div>
            </div>
            <div class="info-item">
                <div class="info-label">Cliente</div>
                <div class="info-valor">{{ reserva.nombre_cliente }}</div>
            </div>
            <div class="info-item">
                <div class="info-label">Email</div>
                <div class="info-valor">{{ reserva.email_cliente }}</div>
            </div>
            <div class="info-item">
                <div class="info-label">Teléfono</div>
                <div class="info-valor">{{ reserva.telefono_cliente|default:"No proporcionado" }}</div>
            </div>
            <div class="info-item">
                <div class="info-label">Barco</div>
                <div class="info-valor">{{ reserva.barco.nombre }}</div>
            </div>
            <div class="info-item">
                <div class="info-label">Cantidad</div>
                <div class="info-valor">{{ reserva.cantidad }}</div>
            </div>
            <div class="info-item">
                <div class="info-label">Fecha de Inicio</div>
                <div class="info-valor">{{ reserva.fecha_inicio }}</div>
            </div>
            <div class="info-item">
                <div class="info-label">Fecha de Fin</div>
                <div class="info-valor">{{ reserva.fecha_fin }}</div>
            </div>
            <div class="info-item">
                <div class="info-label">Precio por Día</div>
                <div class="info-valor">{{ reserva.precio_dia }}€</div>
            </div>
            <div class="info-item">
                <div class="info-label">Tasa Combustible por Día</div>
                <div class="info-valor">{{ reserva.tasa_combustible_dia }}€</div>
            </div>
            <div class="info-item">
                <div class="info-label">Importe Total</div>
                <div class="info-valor">{{ reserva.importe_total }}€</div>
            </div>
            <div class="info-item">
                <div class="info-label">Método de Pago</div>
                <div class="info-valor">{{ reserva.get_metodo_pago_display }}</div>
            </div>
        </div>
    </div>

    {% if transiciones_validas %}
        <div class="cambio-estado">
            <h3>Cambiar Estado</h3>
            <form method="post" action="{% url 'admin_panel:change_reservation_state' reserva.id %}">
                {% csrf_token %}

                <div class="form-group">
                    <label for="nuevo_estado">Nuevo Estado:</label>
                    <select id="nuevo_estado" name="nuevo_estado" required>
                        <option value="">Selecciona un estado</option>
                        {% for estado in transiciones_validas %}
                            <option value="{{ estado }}">{{ estado }}</option>
                        {% endfor %}
                    </select>
                </div>

                <div class="form-group">
                    <label for="notas">Notas (opcional):</label>
                    <textarea id="notas" name="notas" placeholder="Añade notas sobre este cambio de estado"></textarea>
                </div>

                <button type="submit" class="btn-cambiar">Cambiar Estado</button>
            </form>
        </div>
    {% endif %}

    {% if historial %}
        <div class="historial">
            <h3>Historial de Cambios</h3>
            {% for cambio in historial %}
                <div class="historial-item">
                    <div class="historial-fecha">{{ cambio.fecha_cambio|date:"d/m/Y H:i" }}</div>
                    <div class="historial-cambio">{{ cambio.estado_anterior }} → {{ cambio.estado_nuevo }}</div>
                    {% if cambio.notas %}
                        <div class="historial-notas">{{ cambio.notas }}</div>
                    {% endif %}
                </div>
            {% endfor %}
        </div>
    {% endif %}

    <a href="{% url 'admin_panel:reservations_list' %}" class="btn-volver">Volver</a>
</div>
{% endblock %}
